input.command:
PW=admin123password
kubectl -n mongodb exec mongodb-replica-0 -- mongosh --quiet "mongodb://admin-user:$PW@localhost:27017/admin" --eval '
var a = db.getSiblingDB("appdb");
// Create a minimal read role on appdb.reports only
if(!a.getRole("reportsRead")){
  a.createRole({role:"reportsRead", privileges:[{resource:{db:"appdb",collection:"reports"},actions:["find"]}], roles:[]});
  print("created reportsRead");
}
// Grant reports access, revoke raw access
var admin = db.getSiblingDB("admin");
admin.grantRolesToUser("reporting-user", [{role:"reportsRead", db:"appdb"}]);
admin.revokeRolesFromUser("reporting-user", [{role:"rawRead", db:"appdb"}]);
print("=== updated user ===");
printjson(admin.getUser("reporting-user").roles);
'

